code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            long[] D = new long[N];
            for (int i = 0; i < N; i++) {
                D[i] = sc.nextLong();
            }
            long[] prefixSum = new long[N + 1];
            for (int i = 0; i < N; i++) {
                prefixSum[i + 1] = prefixSum[i] + D[i];
            }
            long maxDelish = Long.MIN_VALUE;
            for (int i = 0; i < N; i++) {
                for (int j = i; j < N; j++) {
                    for (int k = j + 1; k < N; k++) {
                        for (int l = k; l < N; l++) {
                            long sum1 = prefixSum[j + 1] - prefixSum[i];
                            long sum2 = prefixSum[l + 1] - prefixSum[k];
                            maxDelish = Math.max(maxDelish, Math.abs(sum1 - sum2));
                        }
                    }
                }
            }
            System.out.println(maxDelish);
        }
    }
}

